def _add_asset_common_arguments(
    parser: argparse.ArgumentParser,
    *,
    choices: list[str],
    include_product_id: bool = True,
) -> None:
    _add_common_adapter_arguments(parser)
    parser.add_argument("--type", dest="asset_type", choices=kebab_choices(choices), required=True)
    if include_product_id:
        parser.add_argument("--product-id")


def _add_asset_list_arguments(parser: argparse.ArgumentParser) -> None:
    _add_asset_common_arguments(parser, choices=ASSET_READ_TYPE_CHOICES)
    parser.add_argument("--page", type=int, default=1)
    parser.add_argument("--page-size", type=int, default=20)
    search_group = parser.add_mutually_exclusive_group()
    search_group.add_argument(
        "--search",
        help=(
            "One free-text search term. For multiple terms, repeat --search-term "
            "instead of joining terms with commas."
        ),
    )
    search_group.add_argument(
        "--search-term",
        action="append",
        dest="search_terms",
        help=(
            "Search term to OR across asset text/tag fields; repeat for multiple "
            f"terms (max {ASSET_SEARCH_TERMS_MAX})."
        ),
    )
    parser.add_argument("--status")
    parser.add_argument("--tag")
    parser.add_argument("--topic-direction-id")
    parser.add_argument("--scope", choices=["all", "workspace", "public"])
    parser.add_argument("--media-type", choices=["image", "video", "audio"])
    parser.add_argument("--source-type")
    parser.add_argument("--no-task-info", action="store_true")
    parser.add_argument("--filters-json")


def _build_asset_list_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload = _load_structured_args(args)
    filters = _dict_value(payload.get("filters"), field="filters") or {}
    if args.filters_json:
        filters.update(_json_object(args.filters_json, flag="--filters-json"))
    if args.search is not None:
        filters["search"] = args.search
    if args.search_terms:
        search_terms = _ordered_strings(args.search_terms)
        if len(search_terms) > ASSET_SEARCH_TERMS_MAX:
            raise ValueError(
                f"asset +list supports at most {ASSET_SEARCH_TERMS_MAX} "
                "--search-term values per request."
            )
        filters["search_terms"] = search_terms
    if args.status is not None:
        filters["status"] = args.status
    if args.tag is not None:
        filters["tag"] = args.tag
    if args.topic_direction_id is not None:
        filters["topic_direction_id"] = args.topic_direction_id
    if args.scope is not None:
        filters["scope"] = args.scope
    page = _dict_value(payload.get("page"), field="page") or {}
    page.update(
        _without_none(
            {
                "page": args.page,
                "page_size": args.page_size,
            }
        )
    )
    if args.media_type is not None:
        filters["media_type"] = args.media_type
    if args.source_type is not None:
        filters["source_type"] = args.source_type
    if args.no_task_info:
        filters["include_task_info"] = False
    payload.update(
        {
            "type": _asset_resource_type(dekebab(args.asset_type)),
            "filters": filters or None,
            "product_id": (
                args.product_id if args.product_id is not None else payload.get("product_id")
            ),
            "page": page,
        }
    )
    return _without_none(payload)


