def _build_asset_write_arguments(args: argparse.Namespace, *, operation: str) -> dict[str, Any]:
    asset_type = dekebab(args.asset_type)
    result = _load_structured_args(args)
    _reject_server_controlled_fields(
        result,
        fields={"analysis_model"},
        context=f"asset +{operation}",
    )
    payload = _dict_value(result.get("payload"), field="payload") or {}
    payload.update(_asset_payload_from_structured_args(args))
    _reject_server_controlled_fields(
        payload,
        fields={"analysis_model"},
        context=f"asset +{operation}",
    )
    payload.update(_asset_payload_from_flags(args, asset_type=asset_type, operation=operation))
    if not payload:
        raise ValueError(f"asset +{operation} requires payload fields or --payload-json.")
    result.update(
        {
            "type": _asset_resource_type(asset_type),
            "payload": payload,
        }
    )
    return _without_none(result)


def _asset_payload_from_structured_args(args: argparse.Namespace) -> dict[str, Any]:
    if args.payload_file:
        return _json_object(
            Path(args.payload_file).read_text(encoding="utf-8"),
            flag="--payload-file",
        )
    if args.payload_json:
        return _json_object(args.payload_json, flag="--payload-json")
    return {}


def _asset_payload_from_flags(
    args: argparse.Namespace, *, asset_type: str, operation: str
) -> dict[str, Any]:
    if asset_type == "product":
        return _product_asset_payload_from_flags(args)
    if asset_type == "persona":
        return _persona_asset_payload_from_flags(args)
    if asset_type == "topic_direction":
        return _topic_direction_asset_payload_from_flags(args)
    if asset_type == "topic":
        return _topic_asset_payload_from_flags(args, operation=operation)
    if asset_type == "format":
        if operation == "update":
            return _format_update_payload_from_flags(args)
        return _format_asset_payload_from_flags(args)
    if asset_type == "media":
        if operation != "create":
            raise ValueError("asset +update does not support --type media.")
        return _media_asset_payload_from_flags(args)
    if asset_type == "bgm":
        return _bgm_asset_payload_from_flags(args, operation=operation)
    if asset_type == "tag":
        return _tag_asset_payload_from_flags(args)
    raise ValueError(f"Unsupported asset type: {asset_type}")


def _product_asset_payload_from_flags(args: argparse.Namespace) -> dict[str, Any]:
    payload = _without_none(
        {
            "name": args.name,
            "description": args.description,
            "website_url": args.website_url,
            "category": args.category,
        }
    )
    assets = _product_assets_from_flags(args)
    if assets:
        payload["assets"] = assets
    _apply_tags_payload(payload, args)
    return payload


def _persona_asset_payload_from_flags(args: argparse.Namespace) -> dict[str, Any]:
    payload = _without_none(
        {
            "name": args.name,
            "description": args.description,
        }
    )
    _apply_tags_payload(payload, args)
    assets = _persona_assets_from_flags(args)
    if assets:
        payload["assets"] = assets
    return payload


def _product_assets_from_flags(args: argparse.Namespace) -> list[dict[str, str]]:
    assets: list[dict[str, str]] = []
    for asset_type, attr_name in (
        ("brand_logo", "brand_logo_media_ids"),
        ("product_image", "product_image_media_ids"),
        ("website_screenshot", "website_screenshot_media_ids"),
        ("app_screenshot", "app_screenshot_media_ids"),
    ):
        for media_id in _ordered_strings(getattr(args, attr_name, None)):
            assets.append({"media_id": media_id, "asset_type": asset_type})
    for value in _ordered_strings(args.asset_media_ids):
        asset_type, media_id = _parse_typed_media_id(value)
        if asset_type not in PRODUCT_ASSET_TYPE_CHOICES:
            raise ValueError(
                "--asset-media-id for product must use one of: "
                f"{', '.join(PRODUCT_ASSET_TYPE_CHOICES)}."
            )
        assets.append({"media_id": media_id, "asset_type": asset_type})
    return assets


def _persona_assets_from_flags(args: argparse.Namespace) -> list[dict[str, str]]:
    assets = [
        {"media_id": media_id, "asset_type": "look_reference"}
        for media_id in _ordered_strings(args.media_ids)
    ]
    for value in _ordered_strings(args.asset_media_ids):
        asset_type, media_id = _parse_typed_media_id(value)
        assets.append({"media_id": media_id, "asset_type": asset_type})
    return assets


def _topic_direction_asset_payload_from_flags(args: argparse.Namespace) -> dict[str, Any]:
    payload = _without_none(
        {
            "title": args.title,
            "description": args.description,
        }
    )
    _apply_tags_payload(payload, args)
    return payload


def _parse_typed_media_id(value: str) -> tuple[str, str]:
    parts = str(value or "").split(":", 1)
    if len(parts) != 2:
        raise ValueError("--asset-media-id must use ASSET_TYPE:MEDIA_ID.")
    asset_type = parts[0].strip()
    media_id = parts[1].strip()
    if not asset_type or not media_id:
        raise ValueError("--asset-media-id must include non-empty ASSET_TYPE and MEDIA_ID.")
    return asset_type, media_id


def _topic_asset_payload_from_flags(args: argparse.Namespace, *, operation: str) -> dict[str, Any]:
    metadata = _metadata_payload(args)
    for key, value in {
        "format_id": args.format_id,
        "persona_id": args.persona_id,
        "persona_experiment_id": args.persona_experiment_id,
    }.items():
        if value is not None:
            metadata[key] = value
    base = _without_none(
        {
            "title": args.title,
            "narrative": args.narrative,
            "topic_direction_id": args.topic_direction_id,
            "status": args.status if operation == "update" else None,
        }
    )
    if args.keywords:
        base["keywords"] = list(args.keywords)
    _apply_tags_payload(base, args)
    if metadata:
        base["metadata"] = metadata
    if operation == "create":
        if not base:
            return {}
        return {"topics": [base]}
    return base


def _metadata_payload(args: argparse.Namespace) -> dict[str, Any]:
    return _json_object(args.metadata_json, flag="--metadata-json") if args.metadata_json else {}


def _apply_tags_payload(payload: dict[str, Any], args: argparse.Namespace) -> dict[str, Any]:
    if getattr(args, "tags", None):
        payload["tags"] = list(args.tags)
    return payload


def _format_asset_payload_from_flags(args: argparse.Namespace) -> dict[str, Any]:
    media_ids = _ordered_strings(args.media_ids)
    urls = _ordered_strings(args.urls)
    format_input = _format_input_from_flags(args)
    if media_ids and urls:
        raise ValueError(
            "asset +create --type format accepts either --url or --media-id, not both."
        )
    if format_input is not None and (media_ids or urls):
        raise ValueError(
            "asset +create --type format accepts --format-input only without --url or --media-id."
        )
    if media_ids:
        return _apply_tags_payload(
            _format_media_payload(
                media_ids=media_ids,
                post_ranges=args.post_ranges,
                instructions=args.instructions,
                publish_on_create=args.publish_on_create,
            ),
            args,
        )
    if urls:
        return _apply_tags_payload(
            _format_url_payload(
                urls=urls,
                requested_source_kind=args.source_kind,
                instructions=args.instructions,
                publish_on_create=args.publish_on_create,
            ),
            args,
        )
    if format_input is not None:
        if args.source_kind not in ("auto", "manual"):
            raise ValueError("--format-input only supports --source-kind auto or manual.")
        payload: dict[str, Any] = {
            "source_kind": "manual",
            "format_input": format_input,
        }
        if args.instructions is not None:
            payload["instructions"] = args.instructions
        if args.publish_on_create:
            payload["publish_on_create"] = True
        return _apply_tags_payload(payload, args)
    return {}


def _format_input_from_flags(args: argparse.Namespace) -> str | None:
    provided = [
        getattr(args, "format_input", None) is not None,
        getattr(args, "format_input_file", None) is not None,
    ]
    if sum(provided) > 1:
        raise ValueError("Use only one of --format-input or --format-input-file.")
    if getattr(args, "format_input", None) is not None:
        return str(args.format_input)
    if getattr(args, "format_input_file", None) is not None:
        return Path(args.format_input_file).read_text(encoding="utf-8")
    return None


def _format_update_payload_from_flags(args: argparse.Namespace) -> dict[str, Any]:
    payload = _without_none({"title": args.title})
    if getattr(args, "is_public", False):
        payload["is_public"] = True
    _apply_tags_payload(payload, args)
    format_json = _format_update_json_from_flags(args)
    if format_json:
        payload["format_json"] = format_json
    return payload


def _format_update_json_from_flags(args: argparse.Namespace) -> dict[str, Any]:
    provided = [
        args.format_json is not None,
        args.format_file is not None,
        args.analysis_markdown is not None,
        args.analysis_file is not None,
    ]
    if sum(provided) > 1:
        raise ValueError(
            "asset +update --type format accepts only one of --format-json, "
            "--format-file, --analysis-markdown, or --analysis-file."
        )
    if args.format_json is not None:
        return _json_object(args.format_json, flag="--format-json")
    if args.format_file is not None:
        return _json_object(
            Path(args.format_file).read_text(encoding="utf-8"),
            flag="--format-file",
        )
    if args.analysis_markdown is not None:
        return {"md": args.analysis_markdown}
    if args.analysis_file is not None:
        return {"md": Path(args.analysis_file).read_text(encoding="utf-8")}
    return {}


def _format_url_payload(
    *,
    urls: list[str],
    requested_source_kind: str,
    instructions: str | None,
    publish_on_create: bool,
) -> dict[str, Any]:
    source_kind = _detect_format_source_kind(urls, requested_source_kind)
    payload: dict[str, Any] = {"source_kind": source_kind}
    if source_kind == "cross_post":
        if len(urls) < 2 or len(urls) > 5:
            raise ValueError(
                "asset +create --type format cross-post mode requires 2-5 --url values."
            )
        non_tiktok_urls = [url for url in urls if not _looks_like_tiktok_url(url)]
        if non_tiktok_urls:
            raise ValueError(
                "asset +create --type format cross-post mode currently supports TikTok URLs."
            )
        payload["tiktok_urls"] = urls
    else:
        if len(urls) != 1:
            raise ValueError(
                "asset +create --type format requires --source-kind cross-post for multiple URLs."
            )
        payload["source_url"] = urls[0]
    if instructions is not None:
        payload["instructions"] = instructions
    if publish_on_create:
        payload["publish_on_create"] = True
    return payload


def _format_media_payload(
    *,
    media_ids: list[str],
    post_ranges: list[str] | None,
    instructions: str | None,
    publish_on_create: bool,
) -> dict[str, Any]:
    payload: dict[str, Any] = {"uploaded_media_ids": media_ids}
    if post_ranges:
        parsed_ranges = [_parse_post_range(value) for value in post_ranges]
        if len(parsed_ranges) < 2 or len(parsed_ranges) > 5:
            raise ValueError(
                "asset +create --type format cross-post mode requires 2-5 --post-range values."
            )
        _validate_post_ranges(post_ranges=parsed_ranges, media_count=len(media_ids))
        payload["source_kind"] = "cross_post"
        payload["uploaded_post_ranges"] = parsed_ranges
    else:
        payload["source_kind"] = "upload"
    if instructions is not None:
        payload["instructions"] = instructions
    if publish_on_create:
        payload["publish_on_create"] = True
    return payload


def _media_asset_payload_from_flags(args: argparse.Namespace) -> dict[str, Any]:
    if args.tags:
        raise ValueError("asset +create --type media does not support --tag.")
    urls = _ordered_strings(args.urls)
    if urls and args.file:
        raise ValueError("asset +create --type media accepts either --url or --file, not both.")
    if len(urls) > 1:
        raise ValueError("asset +create --type media accepts only one --url.")
    if urls:
        return _without_none({"url": urls[0], "source_page_url": args.source_page_url})
    if args.file:
        return _without_none(
            {
                "file": args.file,
                "media_type": args.media_type or "image",
                "title": args.title,
                "description": args.description,
            }
        )
    return {}


def _bgm_asset_payload_from_flags(args: argparse.Namespace, *, operation: str) -> dict[str, Any]:
    urls = _ordered_strings(args.urls)
    if len(urls) > 1:
        raise ValueError("asset +create --type bgm accepts only one --url.")
    payload = _without_none(
        {
            "url": urls[0] if urls else None,
            "title": args.title,
            "description": args.description,
            "status": args.status if operation == "update" else None,
        }
    )
    _apply_tags_payload(payload, args)
    return payload


def _tag_asset_payload_from_flags(args: argparse.Namespace) -> dict[str, Any]:
    return _without_none(
        {
            "name": args.name or args.title,
            "description": args.description,
            "status": args.status,
        }
    )


def _detect_format_source_kind(source_urls: list[str], requested: str) -> str:
    if requested == "cross-post":
        return "cross_post"
    if requested == "manual":
        raise ValueError("--source-kind manual uses --format-input, not --url.")
    if requested != "auto":
        if len(source_urls) > 1:
            raise ValueError(
                "asset +create --type format multiple URLs require --source-kind cross-post."
            )
        return requested
    if len(source_urls) > 1:
        return "cross_post"
    source_url = source_urls[0]
    if _looks_like_instagram_url(source_url):
        return "instagram"
    if _looks_like_tiktok_url(source_url):
        return "tiktok"
    if _looks_like_x_url(source_url):
        return "x"
    if _looks_like_linkedin_url(source_url):
        return "linkedin"
    if _looks_like_xhs_url(source_url):
        return "xhs"
    raise ValueError(
        "asset +create --type format could not infer --source-kind; use "
        "--source-kind tiktok, --source-kind instagram, --source-kind x, "
        "--source-kind linkedin, --source-kind xhs, or --source-kind cross-post."
    )


def _looks_like_instagram_url(source_url: str) -> bool:
    normalized = source_url.lower()
    return "instagram.com" in normalized or "instagr.am" in normalized


def _looks_like_tiktok_url(source_url: str) -> bool:
    normalized = source_url.lower()
    return "tiktok.com" in normalized or "vm.tiktok.com" in normalized


def _looks_like_x_url(source_url: str) -> bool:
    normalized = source_url.lower()
    return "twitter.com" in normalized or "x.com" in normalized


def _looks_like_linkedin_url(source_url: str) -> bool:
    return "linkedin.com" in source_url.lower()


def _looks_like_xhs_url(source_url: str) -> bool:
    normalized = source_url.lower()
    return "xiaohongshu.com" in normalized or "xhslink.com" in normalized


def _parse_post_range(value: str) -> dict[str, int]:
    raw = str(value or "").strip()
    parts = raw.split(":", 1)
    if len(parts) != 2:
        raise ValueError("--post-range must use START:END, e.g. 0:3.")
    try:
        start_index = int(parts[0])
        end_index = int(parts[1])
    except ValueError as exc:
        raise ValueError("--post-range START and END must be integers.") from exc
    if start_index < 0 or end_index <= start_index:
        raise ValueError("--post-range must satisfy 0 <= START < END.")
    return {"start_index": start_index, "end_index": end_index}


def _validate_post_ranges(*, post_ranges: list[dict[str, int]], media_count: int) -> None:
    cursor = 0
    for item in post_ranges:
        if item["start_index"] != cursor:
            raise ValueError("--post-range values must be contiguous from media index 0.")
        if item["end_index"] > media_count:
            raise ValueError("--post-range cannot reference indexes beyond the media-id list.")
        cursor = item["end_index"]
    if cursor != media_count:
        raise ValueError("--post-range values must cover every media-id exactly once.")


def _dict_value(value: Any, *, field: str) -> dict[str, Any] | None:
    if value is None:
        return None
    if not isinstance(value, dict):
        raise ValueError(f"{field} must be a JSON object.")
    return dict(value)


def _asset_resource_type(value: str) -> str:
    return ASSET_RESOURCE_TYPE_BY_PUBLIC[value]


