def _product_write_payload_schema(*, create: bool) -> dict[str, Any]:
    schema: dict[str, Any] = {
        "type": "object",
        "additionalProperties": False,
        "properties": {
            "name": {
                "type": "string",
                "minLength": 1,
                "description": "Product display name.",
            },
            "category": {
                "type": "string",
                "enum": PRODUCT_CATEGORY_CHOICES,
                "description": (
                    "Canonical product category. For intent search and labels, run "
                    "`museoncli asset +options --type product --field category`."
                ),
            },
            "description": {
                "type": "string",
                "minLength": 1,
                "description": "Required product summary.",
            },
            "website_url": {"type": ["string", "null"], "format": "uri"},
            "tags": {
                "type": "array",
                "items": {"type": "string", "minLength": 1},
            },
            "assets": {
                "type": "array",
                "items": {
                    "type": "object",
                    "additionalProperties": False,
                    "properties": {
                        "media_id": {"type": "string", "format": "uuid"},
                        "asset_type": {
                            "type": "string",
                            "enum": PRODUCT_ASSET_TYPE_CHOICES,
                        },
                    },
                    "required": ["media_id", "asset_type"],
                },
            },
        },
    }
    if create:
        schema["required"] = ["name", "category", "description"]
    return schema


def _asset_write_input_schema(*, require_id: bool) -> dict[str, Any]:
    properties: dict[str, Any] = {
        "type": _asset_write_type_property(require_id=require_id),
        "payload": {
            "type": "object",
            "description": (
                "Type-specific asset payload. product create requires name, "
                "category, and description; website_url, tags, and assets are optional. "
                "persona uses name, "
                "description, tags, and assets. "
                "topic_direction uses title, description, and tags. "
                "topic create uses topics=[{title,narrative,topic_direction_id?,"
                "keywords?,tags?,metadata?}]. "
                "format create uses URL, uploaded media, or manual format_input "
                "payloads; source_kind supports tiktok, instagram, x, linkedin, "
                "xhs, upload, manual, and cross_post. The created format's "
                "content_form (the post form it PRODUCES, not the input medium) "
                "is inferred from the source and immutable: image post URL or "
                "uploaded images -> image_post, video -> video_post, manual "
                "format_input text or text-only posts (x/linkedin) -> text_post. "
                "Managed-account (全托管) plan-submit and slideshow generation "
                "accept image_post formats only, so never build a managed-account "
                "format from manual format_input text; use an image-bearing post "
                "URL or uploaded images, then confirm content_form=image_post "
                "via asset +get before submitting; "
                "format update supports title, tags, is_public, and format_json, "
                "including markdown in format_json.md. "
                "media create uses URL import or local file upload payloads. "
                "bgm uses url, title, description, tags, and status."
            ),
        },
        "dry_run": {"type": "boolean", "default": False},
    }
    required = ["type", "payload"]
    if require_id:
        properties["id"] = {"type": "string", "minLength": 1}
        required.insert(1, "id")
    return {
        "type": "object",
        "properties": properties,
        "required": required,
        "allOf": [
            {
                "if": {
                    "properties": {"type": {"const": "product"}},
                    "required": ["type"],
                },
                "then": {
                    "properties": {"payload": _product_write_payload_schema(create=not require_id)}
                },
            }
        ],
    }


