# ---- executors ----
async def _execute_list(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data = ctx.api_data
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    resource_type = str(arguments.get("type") or "")
    filters = arguments.get("filters") if isinstance(arguments.get("filters"), dict) else {}
    page = arguments.get("page") if isinstance(arguments.get("page"), dict) else {}
    page_number = int(page.get("page") or 1)
    page_size = int(page.get("page_size") or 20)
    return await api_data(
        cfg,
        "GET",
        "/agent-cli/assets",
        params=compact_params(
            {
                "type": public_asset_type(resource_type),
                "workspace_id": workspace_id,
                "search": filters.get("search"),
                "search_terms": filters.get("search_terms"),
                "keyword": filters.get("keyword"),
                "tag": filters.get("tag"),
                "topic_direction_id": filters.get("topic_direction_id"),
                "status": filters.get("status"),
                "scope": filters.get("scope"),
                "media_type": filters.get("media_type"),
                "source_type": filters.get("source_type"),
                "page": page_number,
                "page_size": min(max(page_size, 1), 100),
            }
        ),
    )


async def _execute_get(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data = ctx.api_data
    resource_type = str(arguments.get("type") or "")
    resource_id = str(arguments.get("id") or "")
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    return await api_data(
        cfg,
        "GET",
        f"/agent-cli/assets/{public_asset_type(resource_type)}/{resource_id}",
        params={"workspace_id": workspace_id},
    )


async def _execute_get_batch(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data = ctx.api_data
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    return await api_data(
        cfg,
        "POST",
        "/agent-cli/assets/format:batch-get",
        json_body={
            "type": "format",
            "workspace_id": workspace_id,
            "ids": arguments.get("format_ids") or [],
        },
    )


async def _execute_options(ctx: CommandContext) -> Any:
    return await ctx.api_data(
        ctx.cfg,
        "GET",
        "/agent-cli/assets/options",
        params=compact_params(
            {
                "type": ctx.arguments.get("type"),
                "field": ctx.arguments.get("field"),
                "query": ctx.arguments.get("query"),
            }
        ),
    )


async def _execute_write(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    command_name = ctx.spec.schema_name
    api_data = ctx.api_data
    upload_media_file = ctx.upload_media_file
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    resource_type = str(arguments.get("type") or "")
    payload = arguments.get("payload") if isinstance(arguments.get("payload"), dict) else {}
    public_type = public_asset_type(resource_type)
    if command_name == "asset.create":
        if resource_type == "brand_product":
            payload = product_api_payload(payload, workspace_id=workspace_id, create=True)
            payload.pop("workspace_id", None)
            if getattr(ctx.args, "dry_run", False):
                return await api_data(
                    cfg,
                    "POST",
                    "/agent-cli/assets:validate",
                    json_body={
                        "type": public_type,
                        "workspace_id": workspace_id,
                        "payload": payload,
                    },
                )
        elif resource_type == "persona":
            payload = persona_api_payload(payload, workspace_id=workspace_id, create=True)
            payload.pop("workspace_id", None)
        if resource_type == "media":
            if payload.get("file"):
                return await upload_media_file(cfg, workspace_id=workspace_id, arguments=payload)
            payload = {key: value for key, value in payload.items() if key != "workspace_id"}
        return await api_data(
            cfg,
            "POST",
            "/agent-cli/assets",
            json_body={"type": public_type, "workspace_id": workspace_id, "payload": payload},
        )
    if command_name == "asset.update":
        resource_id = str(arguments.get("id") or "")
        if not resource_id:
            raise RuntimeError(f"asset.update {public_type} requires id")
        if resource_type == "brand_product":
            payload = product_api_payload(payload, workspace_id=workspace_id, create=False)
        elif resource_type == "persona":
            payload = persona_api_payload(payload, workspace_id=workspace_id, create=False)
        return await api_data(
            cfg,
            "PATCH",
            f"/agent-cli/assets/{public_type}/{resource_id}",
            json_body={"type": public_type, "workspace_id": workspace_id, "payload": payload},
        )
    raise RuntimeError(f"Unsupported asset write command: {command_name}")


async def _execute_delete(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data = ctx.api_data
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    resource_type = str(arguments.get("type") or "")
    resource_id = str(arguments.get("id") or "")
    if not resource_id:
        raise RuntimeError("asset.delete requires id")
    return await api_data(
        cfg,
        "DELETE",
        f"/agent-cli/assets/{public_asset_type(resource_type)}/{resource_id}",
        params={"workspace_id": workspace_id},
    )


async def _run_read(ctx: CommandContext) -> dict[str, Any]:
    if ctx.spec.schema_name == "asset.list":
        raw = await _execute_list(ctx)
    elif ctx.spec.schema_name == "asset.get-batch":
        raw = await _execute_get_batch(ctx)
    elif ctx.spec.schema_name == "asset.options":
        raw = await _execute_options(ctx)
    else:
        raw = await _execute_get(ctx)
    if raw is None:
        data = await adapter_call(ctx)
        return domain_command_envelope(ctx.spec.schema_name, data)
    raw = add_asset_refs(
        raw, asset_type=getattr(ctx.args, "asset_type", None), site_url=ctx.cfg.site_url
    )
    return direct_api_envelope(ctx.spec.schema_name, ctx.workspace_id, raw)


async def _run_write(ctx: CommandContext) -> dict[str, Any]:
    raw = await _execute_write(ctx)
    if (
        ctx.spec.schema_name == "asset.create"
        and ctx.arguments.get("type") == "slideshow_soul_skin_format"
    ):
        return format_create_envelope(
            ctx.spec.schema_name,
            ctx.workspace_id or "",
            raw.get("asset", raw) if isinstance(raw, dict) else raw,
        )
    # Create/update responses name the resource the reply will surface — attach
    # the same museon.ai ref as the read path so replies can link the resource
    # instead of echoing a bare UUID. add_asset_refs no-ops for non-embeddable
    # types (media/bgm/tag).
    public_type = public_asset_type(str(ctx.arguments.get("type") or ""))
    target = (
        raw.get("asset") if isinstance(raw, dict) and isinstance(raw.get("asset"), dict) else raw
    )
    add_asset_refs(target, asset_type=public_type, site_url=ctx.cfg.site_url)
    return direct_api_envelope(ctx.spec.schema_name, ctx.workspace_id, raw)


EXECUTORS = {
    "asset.list": _run_read,
    "asset.get": _run_read,
    "asset.get-batch": _run_read,
    "asset.options": _run_read,
    "asset.create": _run_write,
    "asset.update": _run_write,
    "asset.delete": direct_enveloped(_execute_delete),
}


def public_asset_type(resource_type: str) -> str:
    mapping = {
        "brand_product": "product",
        "persona": "persona",
        "content_topic_direction": "topic_direction",
        "content_topic": "topic",
        "slideshow_soul_skin_format": "format",
        "media": "media",
        "bgm": "bgm",
        "tag": "tag",
    }
    if resource_type not in mapping:
        raise RuntimeError(f"Unsupported asset type: {resource_type}")
    return mapping[resource_type]


def product_api_payload(
    payload: dict[str, Any],
    *,
    workspace_id: str,
    create: bool,
) -> dict[str, Any]:
    allowed = {"name", "category", "description", "website_url", "tags", "assets"}
    result = strict_payload(payload, allowed=allowed, resource="product")
    if create:
        require_fields(result, fields=("name", "category", "description"), resource="product")
        if "assets" in result:
            validate_assets(result.get("assets"), resource="product", require_nonempty=False)
        result["workspace_id"] = workspace_id
    elif "assets" in result:
        validate_assets(result.get("assets"), resource="product", require_nonempty=False)
    return result


def persona_api_payload(
    payload: dict[str, Any],
    *,
    workspace_id: str,
    create: bool,
) -> dict[str, Any]:
    allowed = {"name", "description", "tags", "assets"}
    result = strict_payload(payload, allowed=allowed, resource="persona")
    if create:
        result["workspace_id"] = workspace_id
    return result


def require_fields(payload: dict[str, Any], *, fields: tuple[str, ...], resource: str) -> None:
    missing = [
        field
        for field in fields
        if field not in payload
        or payload[field] is None
        or (isinstance(payload[field], str) and not payload[field].strip())
        or (isinstance(payload[field], list) and not payload[field])
    ]
    if missing:
        joined = ", ".join(missing)
        raise RuntimeError(f"{resource} payload missing required fields: {joined}")


def validate_assets(value: Any, *, resource: str, require_nonempty: bool) -> None:
    if not isinstance(value, list):
        raise RuntimeError(f"{resource} payload assets must be an array")
    if require_nonempty and not value:
        raise RuntimeError(f"{resource} payload requires at least one asset")
    for index, item in enumerate(value):
        if not isinstance(item, dict):
            raise RuntimeError(f"{resource} asset #{index + 1} must be an object")
        media_id = str(item.get("media_id") or "").strip()
        asset_type = str(item.get("asset_type") or "").strip()
        if not media_id:
            raise RuntimeError(f"{resource} asset #{index + 1} missing media_id")
        if not asset_type:
            raise RuntimeError(f"{resource} asset #{index + 1} missing asset_type")


def strict_payload(
    payload: dict[str, Any],
    *,
    allowed: set[str],
    resource: str,
) -> dict[str, Any]:
    unknown = sorted(set(payload) - allowed)
    if unknown:
        joined = ", ".join(unknown)
        raise RuntimeError(f"{resource} payload has unsupported fields: {joined}")
    return dict(payload)


def validate_asset_write_arguments(
    *,
    workspace_id: str | None,
    arguments: dict[str, Any],
    command_name: str,
) -> None:
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    resource_type = str(arguments.get("type") or "")
    payload = arguments.get("payload") if isinstance(arguments.get("payload"), dict) else {}
    if resource_type == "brand_product":
        product_api_payload(
            payload,
            workspace_id=workspace_id,
            create=command_name == "asset.create",
        )
    elif resource_type == "persona":
        persona_api_payload(
            payload,
            workspace_id=workspace_id,
            create=command_name == "asset.create",
        )
    elif resource_type == "slideshow_soul_skin_format":
        if command_name == "asset.update":
            strict_payload(
                payload,
                allowed={"title", "tags", "is_public", "format_json"},
                resource="format",
            )
        else:
            strict_payload(
                payload,
                allowed={
                    "source_kind",
                    "source_url",
                    "tiktok_urls",
                    "uploaded_media_ids",
                    "uploaded_post_ranges",
                    "instructions",
                    "publish_on_create",
                    "tags",
                    "format_input",
                },
                resource="format",
            )
    elif resource_type == "media":
        strict_payload(
            payload,
            allowed={"url", "source_page_url", "file", "media_type", "title", "description"},
            resource="media",
        )
